use std::{
    path::Path,
    pin::Pin,
    time::{Duration, SystemTime, UNIX_EPOCH},
};

use futures::stream::Stream;
use omega_core::{
    error::ProviderError,
    provider::{ChatChunk, ChatRequest, ChatResponse, LlmProvider, ProviderHealth},
};
use tokio::{fs, process::Command};

#[derive(Clone, Copy)]
pub enum CliKind {
    Codex,
    Claude,
    ,
}

pub struct CliProvider {
    kind: CliKind,
    /// Unique name used for cooldown tracking.  includes the model slug
    /// so each model in the fallthrough chain has its own circuit-breaker slot.
    name: String,

//! OmegaCouncilRouter — fans out to Anthropic +  in parallel, then
//! synthesizes the two responses into a single "omega" reply.
//!
//! Flow:
